        "    \"penalty\": [\"l2\"],\n",
        "    \"solver\": [\"lbfgs\", \"liblinear\"]\n",
        "}\n",
        "\n",
        "grid_log = GridSearchCV(\n",
        "    estimator=log_clf,\n",
        "    param_grid=param_grid,\n",
        "    cv=5,\n",
        "    scoring=\"f1\",\n",
        "    n_jobs=-1,\n",
        "    verbose=1\n",
        ")\n",
